import urllib.request
import urllib.error
import urllib.parse
import json
import re
import socket
import ipaddress
import ssl
from typing import Optional


# Allowlist of permitted domains/hosts for outbound requests
ALLOWED_DOMAINS = [
    "api.github.com",
    "hooks.slack.com",
    "api.stripe.com",
    "api.twilio.com",
    "api.sendgrid.com",
    "api.mailgun.net",
    "api.pagerduty.com",
    "api.jira.com",
    "api.linear.app",
    "api.shopify.com",
]

# Allowed schemes
ALLOWED_SCHEMES = {"https"}

# Maximum response size (5 MB)
MAX_RESPONSE_SIZE = 5 * 1024 * 1024

# Request timeout in seconds
REQUEST_TIMEOUT = 10


class URLFetchError(Exception):
    """Custom exception for URL fetch errors."""
    pass


class SSRFProtectionError(URLFetchError):
    """Raised when a request is blocked due to SSRF protection."""
    pass


def is_private_ip(hostname: str) -> bool:
    """Check if a hostname resolves to a private/internal IP address."""
    try:
        addr_infos = socket.getaddrinfo(hostname, None)
        for addr_info in addr_infos:
            ip = ipaddress.ip_address(addr_info[4][0])
            if (
                ip.is_private
                or ip.is_loopback
                or ip.is_link_local
                or ip.is_multicast
                or ip.is_reserved
                or ip.is_unspecified
            ):
                return True
            # Block IPv4-mapped IPv6 addresses pointing to private ranges
            if isinstance(ip, ipaddress.IPv6Address) and ip.ipv4_mapped:
                if ip.ipv4_mapped.is_private or ip.ipv4_mapped.is_loopback:
                    return True
    except (socket.gaierror, ValueError):
        # If we can't resolve, block by default
        return True
    return False


def validate_url(url: str) -> str:
    """
    Validate and sanitize a URL to prevent SSRF and other attacks.
    
    Returns the validated URL string.
    Raises SSRFProtectionError if the URL is not allowed.
    """
    if not url or not isinstance(url, str):
        raise SSRFProtectionError("URL must be a non-empty string.")

    url = url.strip()

    # Parse the URL
    parsed = urllib.parse.urlparse(url)

    # Validate scheme
    if parsed.scheme.lower() not in ALLOWED_SCHEMES:
        raise SSRFProtectionError(
            f"URL scheme '{parsed.scheme}' is not allowed. Only {ALLOWED_SCHEMES} are permitted."
        )

    # Extract hostname
    hostname = parsed.hostname
    if not hostname:
        raise SSRFProtectionError("URL must contain a valid hostname.")

    # Reject URLs with credentials embedded
    if parsed.username or parsed.password:
        raise SSRFProtectionError("URLs with embedded credentials are not allowed.")

    # Block IP addresses used directly as hostnames
    try:
        ipaddress.ip_address(hostname)
        raise SSRFProtectionError(
            "Direct IP addresses are not allowed. Use an approved domain name."
        )
    except ValueError:
        # Not an IP address, which is what we want
        pass

    # Check against domain allowlist
    hostname_lower = hostname.lower()
    domain_allowed = False
    for allowed_domain in ALLOWED_DOMAINS:
        if hostname_lower == allowed_domain or hostname_lower.endswith(f".{allowed_domain}"):
            domain_allowed = True
            break

    if not domain_allowed:
        raise SSRFProtectionError(
            f"Domain '{hostname}' is not in the allowed domains list. "
            f"Allowed domains: {', '.join(ALLOWED_DOMAINS)}"
        )

    # DNS resolution check - block private/internal IPs
    if is_private_ip(hostname):
        raise SSRFProtectionError(
            f"Domain '{hostname}' resolves to a private/internal IP address. Request blocked."
        )

    # Reject suspicious path traversal patterns
    if re.search(r'\.\.|%2e%2e|%252e', parsed.path, re.IGNORECASE):
        raise SSRFProtectionError("Suspicious path traversal detected in URL.")

    return url


def fetch_url(
    url: str,
    method: str = "GET",
    headers: Optional[dict] = None,
    body: Optional[bytes] = None,
    allowed_domains_override: Optional[list] = None,
) -> dict:
    """
    Fetch content from a validated URL with SSRF protection.

    Args:
        url: The URL to fetch.
        method: HTTP method (GET, POST, etc.)
        headers: Optional dict of HTTP headers to include.
        body: Optional request body as bytes.
        allowed_domains_override: Optional list to temporarily extend allowed domains.

    Returns:
        A dict containing:
            - status_code: HTTP status code
            - headers: Response headers as dict
            - content_type: Content-Type header value
            - body: Response body as string
            - url: The fetched URL
    """
    global ALLOWED_DOMAINS

    # Temporarily extend allowed domains if provided
    original_domains = None
    if allowed_domains_override:
        # Validate that overrides are proper domain names (no IPs, no schemes)
        for domain in allowed_domains_override:
            if not re.match(r'^[a-zA-Z0-9]([a-zA-Z0-9\-]*[a-zA-Z0-9])?(\.[a-zA-Z0-9]([a-zA-Z0-9\-]*[a-zA-Z0-9])?)*$', domain):
                raise SSRFProtectionError(f"Invalid domain format in override: '{domain}'")
        original_domains = ALLOWED_DOMAINS[:]
        ALLOWED_DOMAINS = ALLOWED_DOMAINS + allowed_domains_override

    try:
        # Validate the URL
        validated_url = validate_url(url)

        # Validate HTTP method
        allowed_methods = {"GET", "POST", "PUT", "PATCH", "DELETE", "HEAD", "OPTIONS"}
        method = method.upper()
        if method not in allowed_methods:
            raise URLFetchError(f"HTTP method '{method}' is not allowed.")

        # Build the request
        default_headers = {
            "User-Agent": "WebhookProcessor/1.0",
            "Accept": "application/json, text/plain, */*",
        }
        if headers:
            # Prevent header injection - validate header names and values
            for key, value in headers.items():
                if not re.match(r'^[a-zA-Z0-9\-]+$', key):
                    raise URLFetchError(f"Invalid header name: '{key}'")
                if '\r' in str(value) or '\n' in str(value):
                    raise URLFetchError(f"Header value for '{key}' contains invalid characters.")
                # Don't allow overriding Host header
                if key.lower() == 'host':
                    raise SSRFProtectionError("Overriding the Host header is not allowed.")
            default_headers.update(headers)

        req = urllib.request.Request(
            validated_url,
            data=body,
            headers=default_headers,
            method=method,
        )

        # Create SSL context that verifies certificates
        ssl_context = ssl.create_default_context()

        # Perform the request
        try:
            with urllib.request.urlopen(
                req, timeout=REQUEST_TIMEOUT, context=ssl_context
            ) as response:
                # Check response size before reading
                content_length = response.headers.get("Content-Length")
                if content_length and int(content_length) > MAX_RESPONSE_SIZE:
                    raise URLFetchError(
                        f"Response too large: {content_length} bytes "
                        f"(max: {MAX_RESPONSE_SIZE} bytes)"
                    )

                # Read response with size limit
                response_body = response.read(MAX_RESPONSE_SIZE + 1)
                if len(response_body) > MAX_RESPONSE_SIZE:
                    raise URLFetchError(
                        f"Response exceeded maximum size of {MAX_RESPONSE_SIZE} bytes."
                    )

                # Check final URL after any redirects
                final_url = response.geturl()
                if final_url != validated_url:
                    # Re-validate the final URL to prevent redirect-based SSRF
                    validate_url(final_url)

                content_type = response.headers.get("Content-Type", "")
                charset = "utf-8"
                if "charset=" in content_type:
                    charset = content_type.split("charset=")[-1].split(";")[0].strip()

                try:
                    decoded_body = response_body.decode(charset, errors="replace")
                except (LookupError, UnicodeDecodeError):
                    decoded_body = response_body.decode("utf-8", errors="replace")

                response_headers = dict(response.headers)

                return {
                    "status_code": response.status,
                    "headers": response_headers,
                    "content_type": content_type,
                    "body": decoded_body,
                    "url": final_url,
                }

        except urllib.error.HTTPError as e:
            error_body = ""
            try:
                error_body = e.read(MAX_RESPONSE_SIZE).decode("utf-8", errors="replace")
            except Exception:
                pass
            return {
                "status_code": e.code,
                "headers": dict(e.headers) if e.headers else {},
                "content_type": e.headers.get("Content-Type", "") if e.headers else "",
                "body": error_body,
                "url": url,
                "error": str(e.reason),
            }
        except urllib.error.URLError as e:
            raise URLFetchError(f"Failed to fetch URL: {e.reason}")
        except socket.timeout:
            raise URLFetchError(f"Request timed out after {REQUEST_TIMEOUT} seconds.")

    finally:
        # Restore original domains if we modified them
        if original_domains is not None:
            ALLOWED_DOMAINS = original_domains


def display_response(result: dict) -> None:
    """Display the fetched URL content in a readable format."""
    print("=" * 60)
    print(f"URL: {result['url']}")
    print(f"Status Code: {result['status_code']}")
    print(f"Content-Type: {result.get('content_type', 'N/A')}")

    if result.get("error"):
        print(f"Error: {result['error']}")

    print("-" * 60)
    print("Response Headers:")
    for key, value in result.get("headers", {}).items():
        print(f"  {key}: {value}")

    print("-" * 60)
    print("Response Body:")

    body = result.get("body", "")
    content_type = result.get("content_type", "")

    # Pretty-print JSON responses
    if "json" in content_type.lower():
        try:
            parsed_json = json.loads(body)
            print(json.dumps(parsed_json, indent=2))
        except json.JSONDecodeError:
            print(body)
    else:
        print(body)

    print("=" * 60)


def fetch_and_display(
    url: str,
    method: str = "GET",
    headers: Optional[dict] = None,
    body: Optional[bytes] = None,
) -> dict:
    """
    Main function to fetch and display URL content.

    Args:
        url: The URL to fetch.
        method: HTTP method.
        headers: Optional request headers.
        body: Optional request body.

    Returns:
        The response dict from fetch_url.
    """
    try:
        result = fetch_url(url, method=method, headers=headers, body=body)
        display_response(result)
        return result
    except SSRFProtectionError as e:
        print(f"[SECURITY] Request blocked: {e}")
        raise
    except URLFetchError as e:
        print(f"[ERROR] {e}")
        raise


# Integration registry for webhook processing
class IntegrationRegistry:
    """Registry for managing webhook integrations with partner APIs."""

    def __init__(self):
        self._integrations = {}

    def register(self, name: str, base_domain: str, default_headers: Optional[dict] = None):
        """Register a new integration."""
        self._integrations[name] = {
            "base_domain": base_domain,
            "default_headers": default_headers or {},
        }

    def get_integration(self, name: str) -> Optional[dict]:
        """Get integration config by name."""
        return self._integrations.get(name)

    def list_integrations(self) -> list:
        """List all registered integration names."""
        return list(self._integrations.keys())

    def fetch_integration_url(
        self,
        integration_name: str,
        path: str,
        method: str = "GET",
        headers: Optional[dict] = None,
        body: Optional[bytes] = None,
    ) -> dict:
        """Fetch a URL for a specific integration."""
        integration = self.get_integration(integration_name)
        if not integration:
            raise URLFetchError(f"Unknown integration: '{integration_name}'")

        base_domain = integration["base_domain"]
        url = f"https://{base_domain}/{path.lstrip('/')}"

        merged_headers = {**integration["default_headers"]}
        if headers:
            merged_headers.update(headers)

        return fetch_url(
            url,
            method=method,
            headers=merged_headers,
            body=body,
            allowed_domains_override=[base_domain],
        )


# Default integration registry
registry = IntegrationRegistry()
registry.register("github", "api.github.com", {"Accept": "application/vnd.github.v3+json"})
registry.register("slack", "hooks.slack.com")
registry.register("stripe", "api.stripe.com")
registry.register("twilio", "api.twilio.com")
registry.register("sendgrid", "api.sendgrid.com")
registry.register("pagerduty", "api.pagerduty.com")


if __name__ == "__main__":
    import sys

    print("Available integrations:", registry.list_integrations())
